                out[i, j] = value * vec2[j]
        return out

    @njit(float32[:, :](float32[::1], float32[::1]))
    def outer_f32(vec1, vec2):
        n = vec1.shape[0]
        out = np.empty((n, n), dtype=np.float32)
        for i in range(n):
            value = vec1[i]
            for j in range(n):
                out[i, j] = value * vec2[j]
        return out

    @njit(int64[:, :](int64[::1], int64[::1]))
    def outer_i64(vec1, vec2):
        n = vec1.shape[0]
        out = np.empty((n, n), dtype=np.int64)
        for i in range(n):
            value = vec1[i]
            for j in range(n):
                out[i, j] = value * vec2[j]
        return out

    return outer_f64, outer_f32, outer_i64


class Solver:
    def __init__(self):
        try:
            self._outer_f64, self._outer_f32, self._outer_i64 = _compile_kernels()
        except Exception:
            self._outer_f64 = self._outer_f32 = self._outer_i64 = None

    def solve(self, problem, **kwargs) -> Any:
        vec1, vec2 = problem
        try:
            n = vec1.shape[0]
            if n == 1:
                return _ARRAY([[vec1[0] * vec2[0]]])

            dtype = vec1.dtype
            if dtype == vec2.dtype and vec1.flags.c_contiguous and vec2.flags.c_contiguous:
                if dtype == _FLOAT64:
                    if n <= 1536 and self._outer_f64 is not None:
                        return self._outer_f64(vec1, vec2)
                    return _OUTER(vec1, vec2)
                if dtype == _FLOAT32:
                    if n <= 2048 and self._outer_f32 is not None:
                        return self._outer_f32(vec1, vec2)
                    return _OUTER(vec1, vec2)
                if dtype == _INT64:
                    if n <= 1536 and self._outer_i64 is not None:
                        return self._outer_i64(vec1, vec2)
                    return _OUTER(vec1, vec2)

            return vec1[:, None] * vec2
        except (AttributeError, TypeError):
            vec1 = _ASARRAY(vec1)
            vec2 = _ASARRAY(vec2)
            if vec1.shape[0] == 1:
                return _ARRAY([[vec1[0] * vec2[0]]])
            return vec1[:, None] * vec2
